import time

class LoggerRateLimiter:
    def __init__(self, rate_limit_seconds: float):
        self.rate_limit_seconds = rate_limit_seconds
        self.last_logged_time = {}

    def can_log(self, key: str) -> bool:
        current_time = time.time()
        if key not in self.last_logged_time:
            self.last_logged_time[key] = current_time
            return True
        else:
            time_since_last_log = current_time - self.last_logged_time[key]
            if time_since_last_log >= self.rate_limit_seconds:
                self.last_logged_time[key] = current_time
                return True
            else:
                return False

if __name__ == '__main__':
    limiter = LoggerRateLimiter(rate_limit_seconds=2) # 2 saniyede bir log izni

    print("Deneme 1: 'Hata A' mesajı")
    if limiter.can_log("Hata A"):
        print(f"{time.time()} - Loglandı: Hata A!")
    else:
        print(f"{time.time()} - Engellendi: Hata A!")

    time.sleep(0.5)

